// @hoge1e3/component
import {computed, ReadonlyRefProxy,RefValue,RefValues,get} from "@hoge1e3/ref";
import {Remover} from "@hoge1e3/events";
import {update,nodeRef} from "@hoge1e3/dom-updater";
//const sym_values=Symbol("values");
type RenderedInfo={
  values: any[],
}
const dom2rendered=new Map<string,RenderedInfo>();
const removers=new Map<string, Remover>();
function eqValues(a:any[], b:any[]) {
  return a.every((v,i)=>a[i]===b[i]);
}
export function c<
RS extends readonly ReadonlyRefProxy<unknown>[],
>(
  ...args:[
    any,
    ...res:RS,
    (...values:RefValues<RS>)=>HTMLElement
  ]){
  let domid=args.shift()
  if(!domid)throw new Error("id must be specified");
  domid+="";
  const render=
    args.pop() as
    ((...values:RefValues<RS>)=>HTMLElement)
  const refs=args as unknown as RS
  const values=(refs.map(get)) as RefValues<RS>;
  const dst=document.getElementById(domid);
  if (dst) {
    const valuesOnLastrender=dom2rendered.get(domid)?.values;
    if (valuesOnLastrender && eqValues(valuesOnLastrender, values as any)) {
      return nodeRef(dst);
    }
  }
  const renderAndSet=(...values:RefValues<RS>)=>{
    const dom=render(...values);
    dom.id=domid;
    dom2rendered.set(domid,
      {values:values as any[]});
    return dom;
  }
  const dom=renderAndSet(...values);
  removers.get(domid)?.remove();
  const remover=computed(...refs, (...values)=>values).on("change",({val:values,})=>{
      const dst=document.getElementById(domid);
      if (!dst) {
        remover.remove();
        removers.delete(domid);
        return;
      }
      const valuesOnLastrender=dom2rendered.get(domid)?.values;
      if (valuesOnLastrender && 
      eqValues(valuesOnLastrender, values as any)) {
        return;
      }
      const src=renderAndSet(...values);
      update(dst,src);
  });
  removers.set(domid,remover );
  return dom;
}
